Wrap all localStorage access in a helper:
```js
function safeStorage(fn, fallback) {
  try { return fn() } catch { return fallback }
}
const _stored = safeStorage(() => localStorage.getItem(SHOW_CLOSED_KEY), null)
```
Use the same wrapper in `toggleShowClosed` and `toggleCompact`.

Wrap the updateStatus call in try/catch:
```js
async function handleStatusChange(id, status) {
  const prevStatus = applications.value.find(a => a.id === id)?.status
  try {
    await updateStatus(id, status)
  } catch (err) {
    toast.error('Failed to move application: ' + (err.response?.data?.error || err.message))
    await loadApplications() // force re-sync to undo optimistic UI
    return
  }
  // ... rest of function
}
```

Add try/catch inside the undo action:
```js
action: async () => {
  try {
    await updateStatus(id, prevStatus)
    logoTrigger.value++
    await refreshApplication(id)
  } catch (err) {
    toast.error('Undo failed: ' + (err.response?.data?.error || err.message))
  }
},
```

Use a `watchEffect` or `watch` with `flush: 'post'` to ensure the ref is resolved after the DOM update:
```js
watch(() => props.showClosed, async (val) => {
  if (val) {
    await nextTick()
    // additional tick may be needed if v-if rendering is deferred
    await nextTick()
    closedGroupRef.value?.scrollIntoView({ behavior: 'smooth' })
  }
}, { flush: 'post' })
```
Alternatively verify the ref is populated before calling scrollIntoView and log a warning if not.
